class InMemoryOrderStore:
    def __init__(self) -> None:
        self._orders: Dict[str, OrderRecord] = {}
        self._counter = 0

    def create(self, order_data: Dict[str, Any]) -> OrderRecord:
        self._counter += 1
        order_id = f"ORD-{self._counter:06d}"
        order = OrderRecord(order_id=order_id, **order_data)
        self._orders[order_id] = order
        return order

    def get(self, order_id: str) -> Optional[OrderRecord]:
        return self._orders.get(order_id)


class MockPaymentGateway:
    def charge(self, amount: Decimal, payment_details: PaymentDetails, user: User) -> PaymentResult:
        amount = money(amount)
        if amount < Decimal("0.00"):
            raise PaymentProcessingError("Charge amount cannot be negative.")
        if not payment_details.token:
            raise PaymentProcessingError("Missing payment token.")
        if payment_details.token.startswith("fail_"):
            raise PaymentProcessingError("Payment declined by gateway.")
        transaction_id = f"TXN-{user.user_id}-{payment_details.method}-{str(amount).replace('.', '')}"
        return PaymentResult(
            success=True,
            transaction_id=transaction_id,
            amount_charged=amount,
            provider_response={"status": "approved", "method": payment_details.method},
        )


class CheckoutProcessor:
    def __init__(
        self,
        discount_repository: Optional[Dict[str, DiscountCode]] = None,
        payment_gateway: Optional[MockPaymentGateway] = None,
        order_store: Optional[InMemoryOrderStore] = None,
        tax_rate_provider: Optional[Callable[[User, ValidatedCart], Decimal]] = None,
    ) -> None:
        self.discount_repository = discount_repository or {}
        self.payment_gateway = payment_gateway or MockPaymentGateway()
        self.order_store = order_store or InMemoryOrderStore()
        self.tax_rate_provider = tax_rate_provider or (lambda user, cart: Decimal("0.08"))

    def checkout(
        self,
        user: User,
        cart_items: Sequence[CartItem],
        payment_details: PaymentDetails,
        discount_code: Optional[str] = None,
    ) -> Dict[str, Any]:
        validated_cart = self.validate_cart_items(cart_items)
        discount_result = self.apply_discount_code(user, validated_cart, discount_code)
        tax_result = self.calculate_tax(user, validated_cart, discount_result)
        payment_result = self.process_payment(user, payment_details, tax_result)
        order_record = self.create_order_record(
            user=user,
            validated_cart=validated_cart,
            discount_result=discount_result,
            tax_result=tax_result,
            payment_result=payment_result,
        )
        return {
            "validated_cart": validated_cart,
            "discount_result": discount_result,
            "tax_result": tax_result,
            "payment_result": payment_result,
            "order": order_record,
        }

    def validate_cart_items(self, cart_items: Sequence[CartItem]) -> ValidatedCart:
        if not cart_items:
            raise CartValidationError("Cart is empty.")

        validated_items: List[Dict[str, Any]] = []
        subtotal = Decimal("0.00")
        taxable_subtotal = Decimal("0.00")

        for item in cart_items:
            if item.quantity <= 0:
                raise CartValidationError(f"Invalid quantity for SKU {item.sku}.")
            if item.unit_price < Decimal("0.00"):
                raise CartValidationError(f"Invalid unit price for SKU {item.sku}.")
            if not item.active:
                raise CartValidationError(f"Item {item.sku} is not available.")
            if item.stock < item.quantity:
                raise CartValidationError(f"Insufficient stock for SKU {item.sku}.")

            line_total = money(item.unit_price * item.quantity)
            subtotal += line_total
            if item.taxable:
                taxable_subtotal += line_total

            validated_items.append(
                {
                    "sku": item.sku,
                    "name": item.name,
                    "quantity": item.quantity,
                    "unit_price": item.unit_price,
                    "line_total": line_total,
                    "taxable": item.taxable,
                }
            )

        return ValidatedCart(
            items=validated_items,
            subtotal=money(subtotal),
            taxable_subtotal=money(taxable_subtotal),
        )

    def apply_discount_code(
        self,
        user: User,
        validated_cart: ValidatedCart,
        discount_code: Optional[str],
    ) -> DiscountResult:
        if not discount_code:
            return DiscountResult(
                code=None,
                discount_amount=Decimal("0.00"),
                subtotal_after_discount=validated_cart.subtotal,
                taxable_subtotal_after_discount=validated_cart.taxable_subtotal,
                details={"applied": False},
            )

        code_key = discount_code.strip().upper()
        discount = self.discount_repository.get(code_key)
        if not discount or not discount.active:
            raise DiscountValidationError("Invalid or inactive discount code.")

        self._validate_discount_permissions(user, discount)

        if validated_cart.subtotal < discount.min_subtotal:
            raise DiscountValidationError("Cart subtotal does not meet discount minimum.")

        base_amount = (
            validated_cart.taxable_subtotal
            if discount.applies_to_taxable_only
            else validated_cart.subtotal
        )

        if discount.kind == "percent":
            discount_amount = money(base_amount * (discount.value / Decimal("100")))
        elif discount.kind == "fixed":
            discount_amount = min(money(discount.value), money(base_amount))
        else:
            raise DiscountValidationError("Unsupported discount type.")

        discount_amount = min(discount_amount, validated_cart.subtotal)
        subtotal_after_discount = money(validated_cart.subtotal - discount_amount)

        if validated_cart.subtotal == Decimal("0.00"):
            taxable_discount_share = Decimal("0.00")
        elif discount.applies_to_taxable_only:
            taxable_discount_share = min(discount_amount, validated_cart.taxable_subtotal)
        else:
            ratio = validated_cart.taxable_subtotal / validated_cart.subtotal
            taxable_discount_share = money(discount_amount * ratio)

        taxable_subtotal_after_discount = money(
            max(Decimal("0.00"), validated_cart.taxable_subtotal - taxable_discount_share)
        )

        return DiscountResult(
            code=discount.code,
            discount_amount=money(discount_amount),
            subtotal_after_discount=subtotal_after_discount,
            taxable_subtotal_after_discount=taxable_subtotal_after_discount,
            details={
                "applied": True,
                "kind": discount.kind,
                "value": discount.value,
                "admin_only": discount.admin_only,
                "allowed_tiers": list(discount.allowed_tiers or []),
            },
        )

    def calculate_tax(
        self,
        user: User,
        validated_cart: ValidatedCart,
        discount_result: DiscountResult,
    ) -> TaxResult:
        tax_rate = Decimal(str(self.tax_rate_provider(user, validated_cart)))
        taxable_amount = discount_result.taxable_subtotal_after_discount
        tax_amount = money(taxable_amount * tax_rate)
        total_before_payment = money(discount_result.subtotal_after_discount + tax_amount)

        return TaxResult(
            tax_rate=tax_rate,
            tax_amount=tax_amount,
            total_before_payment=total_before_payment,
        )

    def process_payment(
        self,
        user: User,
        payment_details: PaymentDetails,
        tax_result: TaxResult,
    ) -> PaymentResult:
        return self.payment_gateway.charge(
            amount=tax_result.total_before_payment,
            payment_details=payment_details,
            user=user,
        )

    def create_order_record(
        self,
        user: User,
        validated_cart: ValidatedCart,
        discount_result: DiscountResult,
        tax_result: TaxResult,
        payment_result: PaymentResult,
    ) -> OrderRecord:
        if not payment_result.success:
            raise OrderCreationError("Cannot create order for unsuccessful payment.")

        return self.order_store.create(
            {
                "user_id": user.user_id,
                "items": validated_cart.items,
                "subtotal": validated_cart.subtotal,
                "discount_code": discount_result.code,
                "discount_amount": discount_result.discount_amount,
                "tax_amount": tax_result.tax_amount,
                "total": tax_result.total_before_payment,
                "currency": validated_cart.currency,
                "payment_transaction_id": payment_result.transaction_id,
            }
        )

    def _validate_discount_permissions(self, user: User, discount: DiscountCode) -> None:
        if discount.admin_only and not user.is_admin:
            raise DiscountPermissionError("This discount code is restricted to admins.")

        if discount.allowed_tiers is not None and user.tier not in set(discount.allowed_tiers):
            raise DiscountPermissionError("User tier is not allowed for this discount code.")

        if discount.required_permissions:
            user_permissions = set(user.permissions)
            missing = [perm for perm in discount.required_permissions if perm not in user_permissions]
            if missing:
                raise DiscountPermissionError(
                    f"Missing required permissions for discount code: {', '.join(missing)}"
                )


